def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for c in range(1, 15):
                factor = np.sin(ratio * c) * (c ** 1.8) + np.cos(ratio * c / 2)
                factor *= (1.02 if c % 4 != 0 else 0.95)
                score += max(factor, 0)
            if capacity % 4 == 0 or item % 2 == 1:
                score *= 0.85
            if score > 12:
                score /= 3.2
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 3):
                val = ratio + (n / (n + 2)) ** 1.1
                prod *= val
                if prod > 2e6:
                    prod = np.log1p(prod) * 2
                    break
            mod_val = int(prod * 1.3) % 400
            base = np.sqrt(ratio * mod_val + 3)
            if (int(capacity) % 5 == 0) and ((int(item * 5) + i) % 4 == 0):
                base += 5.5
            else:
                base -= 1.3
            extra = 0
            for x in range(1, 8):
                extra += ((ratio * x**3) % 1) * (x ** 1.9)
            score = base + extra / 4
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 10):
                increment = (ratio ** (m + 3)) * (m ** 3.1) / ((m + 3) ** 0.7)
                score += increment
            remainder = capacity - item
            if remainder < 2:
                score += 12 + remainder * 0.65
            else:
                score -= remainder * 1.1
            if score < -6:
                score = abs(score) * 0.25 + 3
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 22:
                score /= 3.8
        elif 0.5 < ratio <= 0.8:
            penalty_base = 0
            for p in range(1, 12):
                power = (ratio - 0.5) ** p if (ratio - 0.5) > 0 else 0
                penalty_base += power * (p ** 1.8)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.5
                    break
            score = penalty_base * 10
            if capacity < item * 1.02:
                score += 18
            if (int(capacity * 4) % 8 == 0) and (int(item * 7) % 9 == 0):
                score -= 9
            if score < 0:
                score *= -1.2
                score += 7
            if score > 110:
                score = 110
        elif 0.8 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.8
            for q in range(1, 14):
                penalty_ext += ((diff) ** q) * (q ** 3) / (q + 2)
            score = penalty_ext * 22
            if capacity < item * 1.15:
                score += 20
            if (int(capacity * 2) % 7 == 0) and (int(item * 11) % 6 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.75)) % 1) * (z * 1.9)
            if score < 0:
                score = abs(score) * 0.45
            if score > 1400:
                score = 1400
        elif 1.2 < ratio <= 1.7:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 15):
                term = ((diff) ** r) * (r ** 3.5)
                if term > 15000:
                    term = np.cbrt(term)
                super_penalty += term
            score = super_penalty * 27
            if capacity < item * 1.7:
                score += 30
            if (int(capacity * 7) % 5 == 0) and (int(item * 13) % 7 == 0):
                score -= 12
            for w in range(2, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.65 + 6
            if score > 2500:
                score = 2500
        else:
            ultra_penalty = 0
            diff = ratio - 1.7
            for s in range(1, 18):
                term = ((diff) ** s) * (s ** 4)
                if term > 20000:
                    term = np.sqrt(term) * 1.2
                ultra_penalty += term
            score = ultra_penalty * 30
            if capacity < item * 2.5:
                score += 40
            if (int(capacity * 17) % 6 == 0) and (int(item * 23) % 9 == 0):
                score -= 15
            for v in range(3, 11):
                score += ((diff / v) % 1) * (v * 3)
            if score < 0:
                score = abs(score) * 0.7 + 8
            if score > 3500:
                score = 3500
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 8:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count) - median_val * 1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
